@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-icon">✓</span>
                        <span class="step-label">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <span class="step-button" aria-current="@(isCurrent ? "step" : null)">
                        <span class="step-icon">@(step + 1)</span>
                        <span class="step-label">@StepNames[step]</span>
                    </span>
                }
            </li>

            @if (step < StepNames.Length - 1)
            {
                <li class="step-connector @(isCompleted ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="work-entry-editor">
    <div class="entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (ShowRemove)
        {
            <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Company Name *</label>
            <input type="text" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
        </div>
        <div class="form-group">
            <label>Job Title *</label>
            <input type="text" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
        </div>
        <div class="form-group">
            <label>
                <input type="checkbox" checked="@IsCurrent"
                       @onchange="e => ToggleCurrent((bool)e.Value!)" />
                Currently working here
            </label>
            @if (!IsCurrent)
            {
                <label>End Date</label>
                <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { EndDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            }
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        Update(updated);
    }

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);
}

@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" value="@Model.FullName"
               @onchange="e => UpdateModel(Model with { FullName = (string?)e.Value ?? "" })" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" value="@Model.Email"
               @onchange="e => UpdateModel(Model with { Email = (string?)e.Value ?? "" })" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" value="@Model.Phone"
               @onchange="e => UpdateModel(Model with { Phone = (string?)e.Value ?? "" })" />
    </div>

    <div class="form-group">
        <label>Address *</label>
        <textarea rows="2" value="@Model.Address"
                  @onchange="e => UpdateModel(Model with { Address = (string?)e.Value ?? "" })"></textarea>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @(isValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? emailError;
    private bool isValidating;

    [Parameter] public string? Error { get; set; }

    private void UpdateModel(PersonalInfo updated)
    {
        emailError = null;
        OnChanged.InvokeAsync(updated);
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            emailError = null;
            await OnChanged.InvokeAsync(Model); // trigger parent validation message
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address is not valid.";
                return;
            }
            emailError = null;
            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>Work History</h3>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]"
                         Index="index"
                         ShowRemove="Entries.Count > 1"
                         OnChanged="entry => UpdateEntry(index, entry)"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntry>> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public string? Error { get; set; }

    private void UpdateEntry(int index, WorkEntry updated)
    {
        var list = new List<WorkEntry>(Entries);
        list[index] = updated;
        OnChanged.InvokeAsync(list);
    }

    private void RemoveEntry(int index)
    {
        var list = new List<WorkEntry>(Entries);
        list.RemoveAt(index);
        OnChanged.InvokeAsync(list);
    }

    private void AddEntry()
    {
        var list = new List<WorkEntry>(Entries)
        {
            new("", "", DateTime.Today, null, "")
        };
        OnChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        var hasInvalid = Entries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title));
        if (hasInvalid)
        {
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>References</h3>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        var r = References[index];

        <div class="reference-entry">
            <div class="entry-header">
                <h4>Reference @(index + 1)</h4>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn-remove" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="form-row">
                <div class="form-group">
                    <label>Name *</label>
                    <input type="text" value="@r.Name"
                           @onchange="e => UpdateReference(index, r with { Name = (string?)e.Value ?? "" })" />
                </div>
                <div class="form-group">
                    <label>Relationship *</label>
                    <input type="text" value="@r.Relationship"
                           @onchange="e => UpdateReference(index, r with { Relationship = (string?)e.Value ?? "" })" />
                </div>
            </div>
            <div class="form-row">
                <div class="form-group">
                    <label>Email *</label>
                    <input type="email" value="@r.Email"
                           @onchange="e => UpdateReference(index, r with { Email = (string?)e.Value ?? "" })" />
                </div>
                <div class="form-group">
                    <label>Phone *</label>
                    <input type="tel" value="@r.Phone"
                           @onchange="e => UpdateReference(index, r with { Phone = (string?)e.Value ?? "" })" />
                </div>
            </div>
        </div>
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter] public EventCallback<List<Reference>> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public string? Error { get; set; }

    private void UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References);
        list[index] = updated;
        OnChanged.InvokeAsync(list);
    }

    private void RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        OnChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        OnChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        var hasInvalid = References.Any(r =>
            string.IsNullOrWhiteSpace(r.Name) ||
            string.IsNullOrWhiteSpace(r.Relationship) ||
            string.IsNullOrWhiteSpace(r.Email) ||
