@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = !isCompleted && !isCurrent;

            <li class="step-item @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-icon">✓</span>
                        <span class="step-label">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <span class="step-button" aria-current="@(isCurrent ? "step" : null)">
                        <span class="step-icon">@(step + 1)</span>
                        <span class="step-label">@StepNames[step]</span>
                    </span>
                }
            </li>

            @if (step < StepNames.Length - 1)
            {
                <li class="step-connector @(isCompleted ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

