    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]"
                         Index="index"
                         ShowRemove="Entries.Count > 1"
                         OnChanged="entry => UpdateEntry(index, entry)"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntry>> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public string? Error { get; set; }

    private void UpdateEntry(int index, WorkEntry updated)
    {
        var list = new List<WorkEntry>(Entries);
        list[index] = updated;
        OnChanged.InvokeAsync(list);
    }

    private void RemoveEntry(int index)
    {
        var list = new List<WorkEntry>(Entries);
        list.RemoveAt(index);
        OnChanged.InvokeAsync(list);
    }

    private void AddEntry()
    {
        var list = new List<WorkEntry>(Entries)
        {
            new("", "", DateTime.Today, null, "")
        };
        OnChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        var hasInvalid = Entries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title));
        if (hasInvalid)
        {
            return;
        }
        await OnNext.InvokeAsync();
    }
}

