<div class="step-content">
    <h3>Review & Submit</h3>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">✓</div>
            <h4>Application Submitted Successfully!</h4>
            <p>Your application ID is <strong>#@ApplicationId</strong></p>
            <p>We'll be in touch soon. Thank you for applying!</p>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-details">
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <div class="review-dates">
                        @entry.StartDate.ToString("MMM yyyy") —
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> — @r.Relationship
                    <div>@r.Email · @r.Phone</div>
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(SubmitError))
        {
            <div class="validation-error">@SubmitError</div>
        }

        <div class="step-buttons">
            <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
            <button type="button" class="btn-primary btn-submit" @onclick="OnSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter] public string? SubmitError { get; set; }
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}
