@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" value="@Model.FullName"
               @onchange="e => UpdateModel(Model with { FullName = (string?)e.Value ?? "" })" />
    </div>

    <div class="form-group">
        <label>Email *</label>
        <input type="email" value="@Model.Email"
               @onchange="e => UpdateModel(Model with { Email = (string?)e.Value ?? "" })" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>

    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" value="@Model.Phone"
               @onchange="e => UpdateModel(Model with { Phone = (string?)e.Value ?? "" })" />
    </div>

    <div class="form-group">
        <label>Address *</label>
        <textarea rows="2" value="@Model.Address"
                  @onchange="e => UpdateModel(Model with { Address = (string?)e.Value ?? "" })"></textarea>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @(isValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? emailError;
    private bool isValidating;

    [Parameter] public string? Error { get; set; }

    private void UpdateModel(PersonalInfo updated)
    {
        emailError = null;
        OnChanged.InvokeAsync(updated);
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            emailError = null;
            await OnChanged.InvokeAsync(Model); // trigger parent validation message
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address is not valid.";
                return;
            }
            emailError = null;
            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

