@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>References</h3>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        var r = References[index];

        <div class="reference-entry">
            <div class="entry-header">
                <h4>Reference @(index + 1)</h4>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn-remove" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="form-row">
                <div class="form-group">
                    <label>Name *</label>
                    <input type="text" value="@r.Name"
                           @onchange="e => UpdateReference(index, r with { Name = (string?)e.Value ?? "" })" />
                </div>
                <div class="form-group">
                    <label>Relationship *</label>
                    <input type="text" value="@r.Relationship"
                           @onchange="e => UpdateReference(index, r with { Relationship = (string?)e.Value ?? "" })" />
                </div>
            </div>
            <div class="form-row">
                <div class="form-group">
                    <label>Email *</label>
                    <input type="email" value="@r.Email"
                           @onchange="e => UpdateReference(index, r with { Email = (string?)e.Value ?? "" })" />
                </div>
                <div class="form-group">
                    <label>Phone *</label>
                    <input type="tel" value="@r.Phone"
                           @onchange="e => UpdateReference(index, r with { Phone = (string?)e.Value ?? "" })" />
                </div>
            </div>
        </div>
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">
            + Add Reference
        </button>
    }

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = [];
    [Parameter] public EventCallback<List<Reference>> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public string? Error { get; set; }

    private void UpdateReference(int index, Reference updated)
    {
        var list = new List<Reference>(References);
        list[index] = updated;
        OnChanged.InvokeAsync(list);
    }

    private void RemoveReference(int index)
    {
        var list = new List<Reference>(References);
        list.RemoveAt(index);
        OnChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<Reference>(References)
        {
            new("", "", "", "")
        };
        OnChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        var hasInvalid = References.Any(r =>
            string.IsNullOrWhiteSpace(r.Name) ||
            string.IsNullOrWhiteSpace(r.Relationship) ||
            string.IsNullOrWhiteSpace(r.Email) ||
            string.IsNullOrWhiteSpace(r.Phone));
        if (hasInvalid)
        {
            return;
        }
        await OnNext.InvokeAsync();
    }
}

