@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="step-content">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea rows="12" maxlength="@MaxLength" value="@CoverLetter"
                  @oninput="HandleInput"></textarea>
        <div class="char-count @(CurrentLength > MaxLength ? "over-limit" : "")">
            @CurrentLength / @MaxLength characters
        </div>
    </div>

    @if (!string.IsNullOrEmpty(Error))
    {
        <div class="validation-error">@Error</div>
    }

    <div class="step-buttons">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="OnNext">Next</button>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public string? Error { get; set; }

    private int CurrentLength => CoverLetter?.Length ?? 0;

    private void HandleInput(ChangeEventArgs e)
    {
        var value = (string?)e.Value ?? "";
        OnChanged.InvokeAsync(value);
    }
}

