@page "/apply"
@using sv_551648a4e1bd4d5c8410a745f23de446.Models
@using sv_551648a4e1bd4d5c8410a745f23de446.Services
@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              Error="@stepError"
                              ApplicationService="ApplicationService"
                              OnChanged="info => { personalInfo = info; stepError = null; }"
                              OnNext="() => CompleteAndAdvance(0)" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             Error="@stepError"
                             OnChanged="entries => { workEntries = entries; stepError = null; }"
                             OnNext="() => CompleteAndAdvance(1)"
                             OnBack="() => GoToStep(0)" />
            break;

        case 2:
            <ReferencesStep References="references"
                            Error="@stepError"
                            OnChanged="refs => { references = refs; stepError = null; }"
                            OnNext="() => CompleteAndAdvance(2)"
                            OnBack="() => GoToStep(1)" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             Error="@stepError"
                             OnChanged="text => { coverLetter = text; stepError = null; }"
                             OnNext="() => CompleteAndAdvance(3)"
                             OnBack="() => GoToStep(2)" />
            break;

        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        IsSubmitting="isSubmitting"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        SubmitError="@submitError"
                        OnEditSection="GoToStep"
                        OnSubmit="HandleSubmit"
                        OnBack="() => GoToStep(3)" />
            break;
    }
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = [];
    private string? stepError;

    // Step 1
    private PersonalInfo personalInfo = new("", "", "", "");

    // Step 2
    private List<WorkEntry> workEntries = [new("", "", DateTime.Today, null, "")];

    // Step 3
    private List<Reference> references = [new("", "", "", ""), new("", "", "", "")];

    // Step 4
    private string coverLetter = "";

    // Step 5
    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;
    private string? submitError;

    private void GoToStep(int step)
    {
        if (step == currentStep) return;
        // Only allow navigating to completed steps or the current frontier
        if (completedSteps.Contains(step) || step <= currentStep)
        {
            currentStep = step;
            stepError = null;
        }
    }

    private void CompleteAndAdvance(int step)
    {
        // Validate the current step before marking complete
        var error = ValidateStep(step);
        if (error is not null)
        {
            stepError = error;
            return;
        }

        completedSteps.Add(step);
        currentStep = step + 1;
        stepError = null;
    }

    private string? ValidateStep(int step) => step switch
    {
        0 when string.IsNullOrWhiteSpace(personalInfo.FullName) ||
               string.IsNullOrWhiteSpace(personalInfo.Email) ||
               string.IsNullOrWhiteSpace(personalInfo.Phone) ||
               string.IsNullOrWhiteSpace(personalInfo.Address)
            => "Please fill in all required fields.",

        1 when workEntries.Any(e => string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title))
            => "Please fill in company name and job title for all positions.",

        2 when references.Any(r => string.IsNullOrWhiteSpace(r.Name) ||
                                   string.IsNullOrWhiteSpace(r.Relationship) ||
                                   string.IsNullOrWhiteSpace(r.Email) ||
                                   string.IsNullOrWhiteSpace(r.Phone))
            => "Please fill in all fields for each reference.",

        _ => null
    };

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new JobApplication(
                personalInfo,
                new WorkHistory(workEntries),
                references,
                coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

