    color: white;
    border: none;
    padding: 0.65rem 1.5rem;
    border-radius: 0.5rem;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary:hover:not(:disabled) {
    background: #1d4ed8;
}

.btn-primary:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-outline {
    background: white;
    color: #374151;
    border: 1px solid #d1d5db;
    padding: 0.65rem 1.5rem;
    border-radius: 0.5rem;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.15s;
}

.btn-outline:hover {
    background: #f9fafb;
    border-color: #9ca3af;
}

.btn-secondary {
    background: #f3f4f6;
    color: #374151;
    border: 1px solid #e5e7eb;
    padding: 0.5rem 1.25rem;
    border-radius: 0.5rem;
    font-size: 0.9rem;
    cursor: pointer;
    transition: all 0.15s;
    margin-bottom: 1rem;
}

.btn-secondary:hover {
    background: #e5e7eb;
}

.btn-remove {
    background: none;
    border: none;
    color: #dc2626;
    font-size: 0.85rem;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
}

.btn-remove:hover {
    text-decoration: underline;
}

.btn-link {
    background: none;
    border: none;
    color: #2563eb;
    font-size: 0.9rem;
    cursor: pointer;
    padding: 0;
}

.btn-link:hover {
    text-decoration: underline;
}

.btn-submit {
    padding: 0.75rem 2rem;
    font-size: 1rem;
}

