.validation-error {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #dc2626;
    padding: 0.75rem 1rem;
    border-radius: 0.5rem;
    font-size: 0.9rem;
    margin-top: 1rem;
}

.field-error {
    color: #dc2626;
    font-size: 0.8rem;
    margin-top: 0.25rem;
    display: block;
}

/* Work Entry Editor */
.work-entry-editor {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #fafafa;
}

.entry-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.entry-header h4 {
    margin: 0;
    font-size: 1rem;
    color: #374151;
}

/* References */
.reference-entry {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #fafafa;
}

/* Character Count */
.char-count {
    text-align: right;
    font-size: 0.8rem;
    color: #6b7280;
    margin-top: 0.35rem;
}

.char-count.over-limit {
    color: #dc2626;
    font-weight: 600;
}

/* Review Step */
.review-section {
    border: 1px solid #e5e7eb;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-header h4 {
    margin: 0;
    color: #1a1a2e;
}

.review-details {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.35rem 1rem;
    margin: 0;
}

.review-details dt {
    font-weight: 500;
    color: #6b7280;
    font-size: 0.9rem;
}

.review-details dd {
    margin: 0;
    color: #1f2937;
}

.review-work-entry {
    padding: 0.75rem 0;
    border-bottom: 1px solid #f3f4f6;
}

.review-work-entry:last-child {
    border-bottom: none;
}

.review-dates {
    font-size: 0.85rem;
    color: #6b7280;
    margin-top: 0.15rem;
}

.review-reference {
    padding: 0.5rem 0;
    border-bottom: 1px solid #f3f4f6;
}

.review-reference:last-child {
    border-bottom: none;
}

.review-cover-letter {
    white-space: pre-wrap;
    background: #f9fafb;
    padding: 1rem;
    border-radius: 0.375rem;
    line-height: 1.6;
}

/* Confirmation */
.confirmation {
    text-align: center;
    padding: 3rem 1rem;
}

.confirmation-icon {
    width: 4rem;
    height: 4rem;
    background: #10b981;
    color: white;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    margin: 0 auto 1.5rem;
}

.confirmation h4 {
    color: #1a1a2e;
    font-size: 1.4rem;
    margin: 0 0 0.75rem;
}

.confirmation p {
    color: #6b7280;
    font-size: 1.05rem;
}

/* Checkbox styling */
.form-group input[type="checkbox"] {
    margin-right: 0.5rem;
    vertical-align: middle;
}

@media (max-width: 640px) {
    .form-row {
        grid-template-columns: 1fr;
    }

