.apply-page {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.apply-page h2 {
    text-align: center;
    margin-bottom: 2rem;
    color: #1a1a2e;
}

/* Step Indicator */
.step-list {
    display: flex;
    align-items: center;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem;
    gap: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex-shrink: 0;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #d1d5db;
    min-width: 20px;
    margin: 0 0.25rem;
    align-self: center;
    margin-bottom: 1.2rem;
}

