                 <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                        @onchange="e => Update(Entry with { EndDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
             }
         </div>
