@namespace sv_551648a4e1bd4d5c8410a745f23de446.Components.Pages.Apply

<div class="work-entry-editor">
    <div class="entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (ShowRemove)
        {
            <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Company Name *</label>
            <input type="text" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
        </div>
        <div class="form-group">
            <label>Job Title *</label>
            <input type="text" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
        </div>
        <div class="form-group">
            <label>
                <input type="checkbox" checked="@IsCurrent"
                       @onchange="e => ToggleCurrent((bool)e.Value!)" />
                Currently working here
            </label>
            @if (!IsCurrent)
            {
                <label>End Date</label>
                <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { EndDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            }
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void ToggleCurrent(bool isCurrent)
    {
        var updated = isCurrent
            ? Entry with { EndDate = null }
            : Entry with { EndDate = DateTime.Today };
        Update(updated);
    }

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);
}

